), upserted AS (
  INSERT INTO products (name, description, price, image_url, product_info, is_active)
  SELECT name, description, price, image_url, product_info, true
  FROM source_products sp
  WHERE NOT EXISTS (
    SELECT 1 FROM products p WHERE p.product_info->>'id' = sp.slug OR lower(p.name) = lower(sp.name)
  )
  RETURNING id, product_info
), updated AS (
  UPDATE products p
  SET description = COALESCE(p.description, sp.description),
      image_url = COALESCE(p.image_url, sp.image_url),
      product_info = sp.product_info,
      is_active = true
  FROM source_products sp
  WHERE p.product_info->>'id' = sp.slug OR lower(p.name) = lower(sp.name)
  RETURNING p.id, p.product_info
)
SELECT COUNT(*) FROM upserted UNION ALL SELECT COUNT(*) FROM updated;

