    ('sandwich-vegetal', 'EGGS')
), matched_products AS (
  SELECT id, product_info->>'id' AS slug FROM products WHERE product_info ? 'id'
)
INSERT INTO product_allergens (product_id, allergen_id)
SELECT DISTINCT mp.id, a.id
FROM source_allergens sa
JOIN matched_products mp ON mp.slug = sa.slug
JOIN allergens a ON a.code = sa.allergen_code
ON CONFLICT (product_id, allergen_id) DO NOTHING;

COMMIT;